---@class LWonderHudCtrl
local LWonderHudCtrl = LxClass("LWonderHudCtrl",nil)
-----------------------------------------------------------------
LXImport("..Object.LWonderHud")
-----------------------------------------------------------------
function LWonderHudCtrl:LWonderHudCtrl()
    self:InitHud()

    self._cacheHudList = {}
    self._usingHudList = {}

    self._offset = Vector3.New(0.6,1.5,0)
end

function LWonderHudCtrl:InitHud()
    local uiFightRoot = LGameUI.GetUIFight()
    --local hudRootTrans = CS.FindTrans(uiFightRoot,"UIHud")
    self._hudRootTrans = uiFightRoot
end

function LWonderHudCtrl:GetHudRoot()
    return self._hudRootTrans
end

function LWonderHudCtrl:CreateHud(data)
    local uiCam = LGameUI.GetUICamera()
    local sceneCam = gLGameScene:GetCurrentSceneCamera()
    local pos = data.pos + self._offset
    local screenPos = sceneCam:WorldToScreenPoint(pos)
    local uiPos = uiCam:ScreenToWorldPoint(screenPos)

    local huddata =
    {
        root = self._hudRootTrans,
        icon = data.icon,
        text = data.text,
        pos = uiPos,
        onTweenEnd = function(...)
            self:OnTweenEnd(...)
        end
    }

    local hud = table.remove(self._cacheHudList)
    if not hud then
        hud = LWonderHud:New()
    end
    hud:Create(huddata)
    self._usingHudList[hud] = hud
end

function LWonderHudCtrl:OnTweenEnd(hud)
    table.insert(self._cacheHudList,hud)
    self._usingHudList[hud] = nil
end

function LWonderHudCtrl:Destroy()
    for k,v in ipairs(self._cacheHudList) do
        v:Destroy()
    end

    for k,v in pairs(self._usingHudList) do
        k:Destroy()
    end
    self._usingHudList = nil
    self._cacheHudList = nil
end



return LWonderHudCtrl